code = """import json
import re

data_var = locals()['var_function-call-16191237506695086568']
if isinstance(data_var, str) and data_var.endswith('.json'):
    with open(data_var, 'r') as f:
        businesses = json.load(f)
else:
    businesses = data_var

print(f"Total businesses: {len(businesses)}")

# Regex
# Pattern 1: "... in [City], [State], this ..." -> matches ", ST,"
# Note: City names can contain spaces.
# Matches ", ST," followed by something starting with "this" or end of location part.
# The previous regex `,\s([A-Z]{2}),\s+this` worked for "Located at ...".
# Let's try that.
pat1 = re.compile(r'in\s+[^,]+,\s+([A-Z]{2}),') 
# Explanation: "in " + city + ", " + state + ",". City is `[^,]+` (anything but comma).

# Pattern 2: "This [City], [State] location"
pat2 = re.compile(r'This\s+[^,]+,\s+([A-Z]{2})\s+location')

wifi_businesses = []
state_counts = {}
unique_wifi = set()

for b in businesses:
    attrs = b.get('attributes')
    has_wifi = False
    
    if attrs and isinstance(attrs, dict):
        wifi = str(attrs.get('WiFi', ''))
        unique_wifi.add(wifi)
        if 'free' in wifi.lower() or 'paid' in wifi.lower():
            has_wifi = True
    
    if has_wifi:
        desc = b.get('description', '')
        state = None
        
        # Try Pat 1
        m1 = pat1.search(desc)
        if m1:
            state = m1.group(1)
        else:
            # Try Pat 2
            m2 = pat2.search(desc)
            if m2:
                state = m2.group(1)
        
        if state:
            wifi_businesses.append({'state': state, 'business_id': b['business_id']})
            state_counts[state] = state_counts.get(state, 0) + 1

# Find top state
if state_counts:
    top_state = max(state_counts, key=state_counts.get)
    max_count = state_counts[top_state]
else:
    top_state = None
    max_count = 0

# Get business IDs for top state
target_ids = [b['business_id'] for b in wifi_businesses if b['state'] == top_state]

print("__RESULT__:")
print(json.dumps({
    "top_state": top_state,
    "count": max_count,
    "unique_wifi": list(unique_wifi), # Just for debugging
    "sample_target_ids": target_ids[:5],
    "total_target_ids": len(target_ids)
}))"""

